return {
	{
		"nvim-treesitter/nvim-treesitter",
		branch = "main",
		lazy = false,
		build = ":TSUpdate",
		config = function()
			-- Setup de nvim-treesitter (solo si necesitas configurar install_dir)
			require("nvim-treesitter").setup({
				install_dir = vim.fn.stdpath("data") .. "/site",
			})

			-- Instalar parsers
			require("nvim-treesitter").install({
				"lua",
				"vim",
				"vimdoc",
				"query",
				"svelte",
				"python",
				"javascript",
				"typescript",
				"tsx",
				"go",
				"regex",
				"c",
				"html",
				"css",
				"json",
				"yaml",
				"cpp",
				"java",
